scripts.postResponse:
rq.test('Status is 200', function () {
  rq.response.to.have.status(200);
});
let json = {};
try { json = rq.response.json(); } catch (e) {}
rq.test('Access token exists', function () {
  rq.expect(json.access || json.token).to.exist;
});
rq.collectionVariables.set('auth_token', json.access || json.token || '');
